## 2. The C/​C++ stub (`pcapng_stubs.c`)

> **Important** – the file must be compiled with a C++ compiler (e.g. `g++`)
> because it includes the C++ header of *libpcapng*.  The file is named
> `pcapng_stubs.c` but contains a small amount of C++ (wrapped in `extern "C"`).

```c
/* ----------------------------------------------------------------------
   pcapng_stubs.c – C/CPP glue for the OCaml binding
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE               /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

/* ----------------------------------------------------------------------
   Include the (fictional) libpcapng header.  In a real project replace
   this with the actual header that defines the C++ iterator.
   ---------------------------------------------------------------------- */
#include "pcapng.hpp"   /* <-- your real libpcapng header */

/* ----------------------------------------------------------------------
   OCaml representation of the iterator handle.
   ---------------------------------------------------------------------- */
typedef struct {
    pcapng::iterator *it;   /* points to the current element */
    pcapng::iterator *end;  /* sentinel – the “end” iterator */
} ocaml_iterator;

/* ----------------------------------------------------------------------
   Finaliser – called when the OCaml value is GC‑collected.
   ---------------------------------------------------------------------- */
static void finalize_iterator(value v)
{
    ocaml_iterator *o = (ocaml_iterator *)Data_custom_val(v);
    if (o->it)   { delete o->it;   o->it   = NULL; }
    if (o->end)  { delete o->end;  o->end  = NULL; }
}

/* ----------------------------------------------------------------------
   Custom operations for the abstract type `t`.
   ---------------------------------------------------------------------- */
static struct custom_operations iterator_ops = {
    "pcapng.iterator",
    finalize_iterator,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
};

/* ----------------------------------------------------------------------
   Helper: allocate a fresh OCaml value of type `t`.
   ---------------------------------------------------------------------- */
static value alloc_iterator(pcapng::iterator *it, pcapng::iterator *end)
{
    CAMLparam0();
    CAMLlocal1(v);
    v = caml_alloc_custom(&iterator_ops, sizeof(ocaml_iterator), 0, 1);
    ocaml_iterator *o = (ocaml_iterator *)Data_custom_val(v);
    o->it  = it;
    o->end = end;
    CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   OCaml entry point: open_file : string -> t
   ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_open_file(value fname)
{
    CAMLparam1(fname);
    CAMLlocal1(res);
    const char *c_fname = String_val(fname);

    /* The iterator constructor throws on error – translate to Sys_error */
    try {
        pcapng::iterator *it  = new pcapng::iterator(c_fname);
        pcapng::iterator *end = new pcapng::iterator();   /* default‑constructed = end */
        res = alloc_iterator(it, end);
    } catch (const std::exception &e) {
        caml_raise_with_string(*caml_named_value("Sys_error"), e.what());
    }

    CAMLreturn(res);
}

/* ----------------------------------------------------------------------
   OCaml entry point: close : t -> unit
   ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_close(value v_it)
{
    CAMLparam1(v_it);
    ocaml_iterator *o = (ocaml_iterator *)Data_custom_val(v_it);
    if (o->it)  { delete o->it;  o->it = NULL; }
    if (o->end) { delete o->end; o->end = NULL; }
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Helper: build an OCaml `frame` record.
   ---------------------------------------------------------------------- */
static value make_ocaml_frame(const pcapng::frame &f)
{
    CAMLparam0();
    CAMLlocal3(ocaml_rec, ts_val, data_val);

    /* 1. timestamp – int64 */
    ts_val = caml_copy_int64((int64_t)f.ts);

    /* 2. data – a fresh `Bytes.t` copy */
    data_val = caml_alloc_initialized_string(f.len);
    memcpy(String_val(data_val), f.data, f.len);

    /* 3. record { timestamp; data }  (2‑field tuple) */
    ocaml_rec = caml_alloc(2, 0);          /* a record is a 2‑field tuple */
    Store_field(ocaml_rec, 0, ts_val);
    Store_field(ocaml_rec, 1, data_val);

    CAMLreturn(ocaml_rec);
}

/* ----------------------------------------------------------------------
   OCaml entry point: iter : t -> (frame -> unit) -> unit
   ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_iter(value v_it, value v_cb)
{
    CAMLparam2(v_it, v_cb);
    CAMLlocal1(frame_val);

    /* The loop runs in C++ – we must release the OCaml runtime lock
       while walking the iterator so that other OCaml threads can run. */
    caml_release_runtime_system();

    ocaml_iterator *o = (ocaml_iterator *)Data_custom_val(v_it);
    while (*(o->it) != *(o->end)) {
        const pcapng::frame &c_frame = **(o->it);   /* dereference iterator */
        /* Build the OCaml value *outside* the runtime lock. */
        frame_val = make_ocaml_frame(c_frame);

        /* Re‑acquire the runtime to call back into OCaml. */
        caml_acquire_runtime_system();

        /* The callback may raise – propagate the exception and abort the loop. */
        caml_callback_exn(v_cb, frame_val);
        if (Is_exception_result(frame_val)) {
            /* Propagate the exception to the caller. */
            caml_raise(Extract_exception(frame_val));
        }

        /* Drop the runtime again before moving the iterator. */
        caml_release_runtime_system();

        ++(*(o->it));        /* advance to the next frame */
    }

    caml_acquire_runtime_system();   /* final reacquire before returning */
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   OCaml entry point: next_opt : t -> frame option
   ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_next_opt(value v_it)
{
    CAMLparam1(v_it);
    CAMLlocal1(res);

    ocaml_iterator *o = (ocaml_iterator *)Data_custom_val(v_it);
    if (*(o->it) == *(o->end)) {
        /* End of file – raise the OCaml exception defined in the .mli */
        caml_raise_not_found();   /* maps to End_of_file */
    }

    const pcapng::frame &c_frame = **(o->it);
    value ocaml_frame = make_ocaml_frame(c_frame);
    ++(*(o->it));

    /* Build Some ocaml_frame */
    res = caml_alloc(1, 0);          /* Some = a one‑field constructor */
    Store_field(res, 0, ocaml_frame);
    CAMLreturn(res);
}

/* ----------------------------------------------------------------------
   Register the exception name `End_of_file`.  The .mli declares it as
   an exception, so the stub must bind a name for it.
   ---------------------------------------------------------------------- */
static struct caml_named_value end_of_file_exn = {
    .name = "Pcapng.End_of_file",
    .value = Val_int(0)   /* placeholder – never used */
};

CAMLprim value caml_pcapng_register_exn(value unit)
{
    caml_register_named_value(end_of_file_exn.name, end_of_file_exn.value);
    return Val_unit;
}
```

### 2.1  How the stub works

| OCaml side | C stub side | Remarks |
|------------|-------------|---------|
| `type t`   | a **custom block** (`ocaml_iterator`) that stores two pointers (`it` and `end`). | The block is finalised automatically, releasing the C++ objects. |
| `open_file`| `new pcapng::iterator(fname)` + `new pcapng::iterator()` for the sentinel. | Any C++ exception is turned into `Sys_error`. |
| `close`    | `delete` the two C++ objects. | Idempotent – safe to call even on a partially‑initialised handle. |
| `iter`     | A tight C++ `while` loop that: <br>1. builds a fresh OCaml `frame` record, <br>2. reacquires the OCaml runtime, <br>3. calls the user’s closure, <br>4. checks for exceptions, <br>5. advances the iterator. | The loop runs *outside* the OCaml runtime, so other OCaml threads are not blocked. |
| `next_opt` | Same as `iter` but returns a single `Some frame` or raises `End_of_file`. | Slower than `iter` – provided for completeness. |
| Exceptions | `End_of_file` is registered under the name `"Pcapng.End_of_file"` and raised from `next_opt`. | The `iter` function simply propagates whatever exception the callback raises. |

